If I send the following request for `salbrut`, `sali`, `salnet`, `sal_h_b` from a monthly `sali` to OpenFisca:

    {"scenarios":[{"test_case":{"familles":[{"parents":["ind0"]}],"foyers_fiscaux":[{"declarants":["ind0"]}],"individus":[{"activite":"Actif occupé","type_sal":"prive_cadre","sali":{"2014-11":1000},"id":"ind0"}],"menages":[{"personne_de_reference":"ind0"}]},"legislation_url":"http://api.openfisca.fr/api/1/default-legislation","period":"month:2014-11"}],"variables":["salbrut","sali","salnet","sal_h_b"]}

